// validation.js
// Reusable input-validation helpers for the API.
//
// Each low-level validator returns either `null` (valid) or a string describing
// the problem. Higher-level schema validators collect those strings into an
// array so callers can return a descriptive 400 response that lists every
// failed validation at once.

// RFC 5321 caps the full email address length at 254 characters. This regex is
// intentionally pragmatic (not a full RFC 5322 implementation): one or more
// non-whitespace/non-@ chars, an @, a domain with at least one dot, and a TLD
// of 2+ chars. Good enough to reject obviously malformed input while remaining
// predictable.
const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]{2,}$/;

const MAX_EMAIL_LENGTH = 254;
const MIN_NAME_LENGTH = 1;
const MAX_NAME_LENGTH = 100;

/**
 * Assert a required field is present (not undefined, not null, not empty string).
 */
function validateRequired(value, fieldName) {
  if (value === undefined || value === null || value === '') {
    return `${fieldName} is required`;
  }
  return null;
}

/**
 * Assert the value is a numeric id (positive integer). Accepts either a
 * JS number or a string that parses cleanly to a positive integer — Express
 * route params arrive as strings, so we normalise here.
 */
function validateId(value, fieldName = 'id') {
  if (value === undefined || value === null || value === '') {
    return `${fieldName} is required`;
  }
  // Reject booleans, arrays, objects, etc.
  if (typeof value !== 'number' && typeof value !== 'string') {
    return `${fieldName} must be numeric`;
  }
  const str = String(value).trim();
  // Must be all digits (no decimals, no signs, no whitespace inside).
  if (!/^\d+$/.test(str)) {
    return `${fieldName} must be numeric`;
  }
  const n = Number(str);
  if (!Number.isInteger(n) || n <= 0) {
    return `${fieldName} must be a positive integer`;
  }
  return null;
}

/**
 * Assert the value is a string between minLen and maxLen (inclusive) chars.
 */
function validateString(value, fieldName, { minLen = 0, maxLen = Infinity } = {}) {
  if (typeof value !== 'string') {
    return `${fieldName} must be a string`;
  }
  if (value.length < minLen) {
    return `${fieldName} must be at least ${minLen} character(s)`;
  }
  if (value.length > maxLen) {
    return `${fieldName} must be at most ${maxLen} character(s)`;
  }
  return null;
}

/**
 * Assert the value looks like an email and respects the max length cap.
 */
function validateEmail(value, fieldName = 'email') {
  if (typeof value !== 'string') {
    return `${fieldName} must be a string`;
  }
  if (value.length > MAX_EMAIL_LENGTH) {
    return `${fieldName} must be at most ${MAX_EMAIL_LENGTH} character(s)`;
  }
  if (!EMAIL_REGEX.test(value)) {
    return `${fieldName} must be a valid email address`;
  }
  return null;
}

/**
 * Validate a `name` field per the spec: required string, 1–100 chars.
 * Returns an array of error strings (empty when valid).
 */
function validateName(value, fieldName = 'name') {
  const errors = [];
  const missing = validateRequired(value, fieldName);
  if (missing) {
    errors.push(missing);
    return errors;
  }
  const typeOrLen = validateString(value, fieldName, {
    minLen: MIN_NAME_LENGTH,
    maxLen: MAX_NAME_LENGTH,
  });
  if (typeOrLen) errors.push(typeOrLen);
  return errors;
}

/**
 * Validate an `email` field: required, string, valid format, <= 254 chars.
 * Returns an array of error strings (empty when valid).
 */
function validateEmailField(value, fieldName = 'email') {
  const errors = [];
  const missing = validateRequired(value, fieldName);
  if (missing) {
    errors.push(missing);
    return errors;
  }
  const err = validateEmail(value, fieldName);
  if (err) errors.push(err);
  return errors;
}

// --- Schema-level validators --------------------------------------------

/**
 * Validate a user id coming from a route/query param.
 * @returns {string[]} list of error messages (empty = valid).
 */
function validateUserIdParam(rawId) {
  const err = validateId(rawId, 'id');
  return err ? [err] : [];
}

/**
 * Validate the body for creating a user. Requires `name` and `email`.
 */
function validateCreateUserBody(body) {
  const errors = [];
  if (body === null || typeof body !== 'object' || Array.isArray(body)) {
    return ['request body must be a JSON object'];
  }
  errors.push(...validateName(body.name));
  errors.push(...validateEmailField(body.email));
  return errors;
}

/**
 * Validate the body for updating a user. `name` and `email` are optional
 * individually, but at least one must be provided. When present, each must
 * satisfy its field-level rules.
 */
function validateUpdateUserBody(body) {
  const errors = [];
  if (body === null || typeof body !== 'object' || Array.isArray(body)) {
    return ['request body must be a JSON object'];
  }
  const hasName = body.name !== undefined;
  const hasEmail = body.email !== undefined;
  if (!hasName && !hasEmail) {
    return ['at least one of name or email must be provided'];
  }
  if (hasName) errors.push(...validateName(body.name));
  if (hasEmail) errors.push(...validateEmailField(body.email));
  return errors;
}

/**
 * Express helper: send a 400 response with the validation errors, or return
 * false if there are none so the caller can continue.
 *
 *   if (sendIfInvalid(res, errors)) return;
 */
function sendIfInvalid(res, errors) {
  if (errors && errors.length > 0) {
    res.status(400).json({
      error: 'ValidationError',
      message: 'Request failed validation',
      details: errors,
    });
    return true;
  }
  return false;
}

module.exports = {
  // constants (exported for tests / reuse)
  EMAIL_REGEX,
  MAX_EMAIL_LENGTH,
  MIN_NAME_LENGTH,
  MAX_NAME_LENGTH,
  // primitives
  validateRequired,
  validateId,
  validateString,
  validateEmail,
  validateName,
  validateEmailField,
  // schemas
  validateUserIdParam,
  validateCreateUserBody,
  validateUpdateUserBody,
  // express helper
  sendIfInvalid,
};

