// Validation helper module
// Provides reusable validators and a runner that collects all failures
// so route handlers can return descriptive 400 errors.

// RFC 5321 caps the entire address at 254 characters; we enforce that here.
const EMAIL_MAX_LENGTH = 254;
const NAME_MIN_LENGTH = 1;
const NAME_MAX_LENGTH = 100;

// Pragmatic email regex: requires local@domain.tld with no whitespace.
// Not a full RFC 5322 validator, but rejects the common malformed cases.
const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

/**
 * Validate that a required field is present (not undefined, null, or empty string).
 * @returns {string|null} error message, or null if valid
 */
function validateRequired(value, fieldName) {
  if (value === undefined || value === null || value === '') {
    return `${fieldName} is required`;
  }
  return null;
}

/**
 * Validate that a value is numeric (either a number or a string parseable as an integer).
 * Accepts strings because route params always arrive as strings.
 * @returns {string|null} error message, or null if valid
 */
function validateNumericId(value, fieldName = 'id') {
  if (value === undefined || value === null || value === '') {
    return `${fieldName} is required`;
  }
  // Reject booleans (typeof true === 'number' is false, but be explicit)
  if (typeof value === 'boolean') {
    return `${fieldName} must be numeric`;
  }
  const asString = String(value).trim();
  if (!/^-?\d+$/.test(asString)) {
    return `${fieldName} must be numeric`;
  }
  const parsed = Number(asString);
  if (!Number.isFinite(parsed) || !Number.isInteger(parsed)) {
    return `${fieldName} must be numeric`;
  }
  return null;
}

/**
 * Validate that a value is a string within optional length bounds.
 * @returns {string|null} error message, or null if valid
 */
function validateString(value, fieldName, { min, max } = {}) {
  if (typeof value !== 'string') {
    return `${fieldName} must be a string`;
  }
  if (min !== undefined && value.length < min) {
    return `${fieldName} must be at least ${min} character${min === 1 ? '' : 's'}`;
  }
  if (max !== undefined && value.length > max) {
    return `${fieldName} must be at most ${max} characters`;
  }
  return null;
}

/**
 * Validate that a value is a string matching email format and within the length cap.
 * @returns {string|null} error message, or null if valid
 */
function validateEmail(value, fieldName = 'email') {
  if (typeof value !== 'string') {
    return `${fieldName} must be a string`;
  }
  if (value.length > EMAIL_MAX_LENGTH) {
    return `${fieldName} must be at most ${EMAIL_MAX_LENGTH} characters`;
  }
  if (!EMAIL_REGEX.test(value)) {
    return `${fieldName} must be a valid email address`;
  }
  return null;
}

/**
 * Validate a name field: required string, 1-100 chars.
 * @returns {string[]} list of error messages (empty if valid)
 */
function validateName(value, fieldName = 'name') {
  const errors = [];
  const requiredErr = validateRequired(value, fieldName);
  if (requiredErr) {
    errors.push(requiredErr);
    return errors;
  }
  const stringErr = validateString(value, fieldName, {
    min: NAME_MIN_LENGTH,
    max: NAME_MAX_LENGTH,
  });
  if (stringErr) errors.push(stringErr);
  return errors;
}

/**
 * Run a list of validators and collect all errors.
 * Each validator is either a function returning string|null/string[], or an
 * already-computed error value. This lets route handlers declare the full
 * validation surface in one place.
 *
 * @param {Array<string|string[]|null|undefined|(() => string|string[]|null)>} checks
 * @returns {string[]} flattened list of error messages
 */
function collectErrors(checks) {
  const errors = [];
  for (const check of checks) {
    const result = typeof check === 'function' ? check() : check;
    if (!result) continue;
    if (Array.isArray(result)) {
      for (const msg of result) if (msg) errors.push(msg);
    } else {
      errors.push(result);
    }
  }
  return errors;
}

/**
 * Express middleware-style helper: if `errors` is non-empty, send a 400 response
 * and return true (signaling the caller to stop). Otherwise return false.
 */
function sendValidationError(res, errors) {
  if (errors.length === 0) return false;
  res.status(400).json({
    error: 'Validation failed',
    details: errors,
  });
  return true;
}

module.exports = {
  validateRequired,
  validateNumericId,
  validateString,
  validateEmail,
  validateName,
  collectErrors,
  sendValidationError,
  // Exported for tests / reuse
  EMAIL_MAX_LENGTH,
  NAME_MIN_LENGTH,
  NAME_MAX_LENGTH,
  EMAIL_REGEX,
};

