const NAME_MAX = 100;
const EMAIL_MAX = 254;

function isPresent(value) {
  return value !== undefined && value !== null && value !== '';
}

function validateRequired(value, field) {
  if (!isPresent(value)) {
    return `${field} is required`;
  }
  return null;
