  // Accept numbers or numeric strings; reject NaN, Infinity, non-integers,
  // and non-positive values (ids are expected to be positive integers).
  const asNumber = typeof value === 'number' ? value : Number(value);
  if (!Number.isFinite(asNumber) || !Number.isInteger(asNumber)) {
    return `${field} must be a numeric integer`;
  }
  if (asNumber <= 0) {
    return `${field} must be a positive integer`;
  }
  return null;
}

function validateName(value, field = 'name') {
  if (!isPresent(value)) {
    return `${field} is required`;
  }
  if (typeof value !== 'string') {
    return `${field} must be a string`;
  }
  if (value.length < NAME_MIN || value.length > NAME_MAX) {
    return `${field} must be between ${NAME_MIN} and ${NAME_MAX} characters`;
  }
  return null;
}

function validateEmail(value, field = 'email') {
  if (!isPresent(value)) {
    return `${field} is required`;
  }
  if (typeof value !== 'string') {
    return `${field} must be a string`;
  }
  if (value.length > EMAIL_MAX) {
    return `${field} must be at most ${EMAIL_MAX} characters`;
  }
  if (!EMAIL_REGEX.test(value)) {
    return `${field} must be a valid email address`;
  }
  return null;
}

/**
 * Runs an ordered list of [validatorFn, value, fieldName] tuples and
 * returns an array of error messages. An empty array means the input
 * is valid.
 */
function runValidators(checks) {
  const errors = [];
  for (const [fn, value, field] of checks) {
    const err = fn(value, field);
    if (err) errors.push(err);
  }
  return errors;
}

/**
 * Express helper: if `errors` is non-empty, send a descriptive 400
 * response and return true (indicating the caller should stop).
 * Returns false otherwise.
 */
function sendValidationErrors(res, errors) {
  if (errors.length > 0) {
    res.status(400).json({
      error: 'Validation failed',
      details: errors,
    });
    return true;
  }
  return false;
}

module.exports = {
  // Individual validators
  validateRequired,
  validateNumericId,
  validateName,
  validateEmail,
  // Helpers
  runValidators,
  sendValidationErrors,
  // Constants (exported so tests / callers can reuse limits)
  NAME_MIN,
  NAME_MAX,
  EMAIL_MAX,
  EMAIL_REGEX,
};

